import{D as n,c as a,F as o,E as l,a4 as c,o as t,I as h}from"./chunks/framework.DE27HZwE.js";const s=c('<h1 id="介绍" tabindex="-1">介绍 <a class="header-anchor" href="#介绍" aria-label="Permalink to &quot;介绍&quot;">​</a></h1><p>FC-Admin是一款开源免费且开箱即用的中后台管理系统模版。使用了最新的 Vue3、Vite、Element-Plus、TypeScript、Pinia 等主流技术开发。助您加快开发速度，节省大量时间成本。</p><h2 id="在线预览" tabindex="-1">在线预览 <a class="header-anchor" href="#在线预览" aria-label="Permalink to &quot;在线预览&quot;">​</a></h2><p><a href="https://www.fcadmin.fun" target="_blank" rel="noreferrer">https://www.fcadmin.fun</a></p><h2 id="完整版本" tabindex="-1">完整版本 <a class="header-anchor" href="#完整版本" aria-label="Permalink to &quot;完整版本&quot;">​</a></h2><p>GitHub：<a href="https://github.com/lfcleo/fc-admin" target="_blank" rel="noreferrer">https://github.com/lfcleo/fc-admin</a><br> Gitee：<a href="https://gitee.com/lfcleo/fc-admin" target="_blank" rel="noreferrer">https://gitee.com/lfcleo/fc-admin</a></p><h2 id="精简版本" tabindex="-1">精简版本 <a class="header-anchor" href="#精简版本" aria-label="Permalink to &quot;精简版本&quot;">​</a></h2><p>精简版是基于 FC-Admin 提炼出的架子，包含主体功能，更适合实际项目开发。开发者只需要在此项目上做“加法”开发，无需从完整版做“减法”。</p><p>GitHub：<a href="https://github.com/lfcleo/fc-admin-thin" target="_blank" rel="noreferrer">https://github.com/lfcleo/fc-admin-thin</a><br> Gitee：<a href="https://gitee.com/lfcleo/fc-admin-thin" target="_blank" rel="noreferrer">https://gitee.com/lfcleo/fc-admin-thin</a></p><h2 id="基于fc-admin开发的优秀项目-排名不分先后-欢迎投稿" tabindex="-1">基于FC-Admin开发的优秀项目(排名不分先后，欢迎投稿) <a class="header-anchor" href="#基于fc-admin开发的优秀项目-排名不分先后-欢迎投稿" aria-label="Permalink to &quot;基于FC-Admin开发的优秀项目(排名不分先后，欢迎投稿)&quot;">​</a></h2><p>空位中...</p><h2 id="灵感来源" tabindex="-1">灵感来源 <a class="header-anchor" href="#灵感来源" aria-label="Permalink to &quot;灵感来源&quot;">​</a></h2><p>本项目基于<a href="https://gitee.com/lolicode/scui" target="_blank" rel="noreferrer">SCUI</a>开发。由于 SCUI 作者已经好久没维护，所以 FC-Admin 基于 SCUI 的样式，从零搭建代码开发，使用了最新的技术栈，并修复了 SCUI 中的 bug。在这里感谢 SCUI 作者的开源项目。</p><p>FC-Admin将会持续更新，修复 bug，增加新功能，欢迎 Star 和 Issues。</p><h2 id="维护者" tabindex="-1">维护者 <a class="header-anchor" href="#维护者" aria-label="Permalink to &quot;维护者&quot;">​</a></h2>',15),b=JSON.parse('{"title":"介绍","description":"","frontmatter":{},"headers":[],"relativePath":"guide/base/introduce.md","filePath":"zh/guide/base/introduce.md"}'),d={name:"guide/base/introduce.md"},_=Object.assign(d,{setup(m){const r=[{src:"https://avatars.githubusercontent.com/u/17870701?v=4",title:"Leo",link:"https://github.com/lfcleo"}];return(f,u)=>{const i=n("Avatar");return t(),a("div",null,[s,(t(),a(o,null,l(r,e=>h(i,{src:e.src,title:e.title,link:e.link},null,8,["src","title","link"])),64))])}}});export{b as __pageData,_ as default};
